#include <bits/stdc++.h>
#define int long long
using namespace std;
int num[12], len;
int l, r, dp[11][11][11][2][2][2][2];
int f (int p, int a, int b, bool c, bool d, bool _4, bool _8) {
	if (_4 && _8) {
		return 0;
	}
	if (p <= 0) {
		return c;
	}
	if (~dp[p][a][b][c][d][_4][_8]) {
		return dp[p][a][b][c][d][_4][_8];
	}
	int res = 0, lim = !d ? num[p] : 9;
	for (int i = 0; i <= lim; i++) {
		res += f (p - 1, i, a, c || (i == b && i == a), d || (i < lim), _4 || (i == 4), _8 || (i == 8));
	}
	return dp[p][a][b][c][d][_4][_8] = res;
}
int calc(int x){
	if (x < 1e10) {
		return 0;
	}
    memset (dp, -1, sizeof (dp));
    for (len = 0; x; x /= 10) {
    	num[++len] = x % 10;
	}
	int res = 0;
	for (int i = 1; i <= num[len]; i++) {
		res += f(10, i, 0, 0, i < num[len], i == 4, i == 8);
	}
	return res;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	int l, r;
	cin >> l >> r;
	cout << calc (r) - calc (l - 1);
	return 0;
}
